import{_ as r,H as o,f as n,i as l}from"./chunks/framework.DLd0CbzH.js";const y=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ai/resultresort.md","filePath":"ai/resultresort.md","lastUpdated":1780495817000}'),a={name:"ai/resultresort.md"};function t(p,s,g,e,i,c){return o(),n("div",null,[...s[0]||(s[0]=[l('<h2 id="原因" tabindex="-1"><span style="color:rgb(15, 17, 21);">原因</span> <a class="header-anchor" href="#原因" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;原因&lt;/span&gt;&quot;">​</a></h2><p><span style="color:rgb(15, 17, 21);">LLM本身需要对检索结果进行重排，主要是因为</span><strong><span style="color:rgb(15, 17, 21);">初步检索的“粗糙性”</span></strong><span style="color:rgb(15, 17, 21);">和</span><strong><span style="color:rgb(15, 17, 21);">LLM的“敏感体质”</span></strong><span style="color:rgb(15, 17, 21);">之间存在巨大鸿沟。简单来说，就是把未经整理的搜索结果直接扔给大模型，既浪费模型的“脑力”，又容易让它犯错。</span></p><p><span style="color:rgb(15, 17, 21);">我们可以从以下三个核心原因来理解：</span></p><h3 id="_1-对抗大模型的-金鱼记忆-与注意力偏见" tabindex="-1"><span style="color:rgb(15, 17, 21);">1. 对抗大模型的“金鱼记忆”与注意力偏见</span> <a class="header-anchor" href="#_1-对抗大模型的-金鱼记忆-与注意力偏见" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;1. 对抗大模型的“金鱼记忆”与注意力偏见&lt;/span&gt;&quot;">​</a></h3><p><span style="color:rgb(15, 17, 21);">这是</span><strong><span style="color:rgb(15, 17, 21);">最本质</span></strong><span style="color:rgb(15, 17, 21);">的原因。</span></p><ul><li><strong><span style="color:rgb(15, 17, 21);">“迷失在中间”（Lost in the Middle）现象</span></strong><span style="color:rgb(15, 17, 21);">：大量研究表明，LLM对输入文本的注意力是</span><strong><span style="color:rgb(15, 17, 21);">U形曲线</span></strong><span style="color:rgb(15, 17, 21);">。它最擅长记住开头和结尾的信息，但对中间部分的内容会明显“失忆”。如果最相关的文档恰好排在检索列表的第15位（总共20个文档），它极有可能被模型忽略，导致答案质量暴跌。</span></li><li><strong><span style="color:rgb(15, 17, 21);">位置偏见（Position Bias）</span></strong><span style="color:rgb(15, 17, 21);">：LLM天然地更信赖出现在序列前端的文档。如果一个次相关的文档排在首位，模型可能会以此为据生成一个次优答案，甚至产生幻觉。重排的核心任务，就是</span><strong><span style="color:rgb(15, 17, 21);">打破这种糟糕的初始顺序，将“含金量最高”的文档强制推到LLM的注意力焦点区（开头和结尾）</span></strong><span style="color:rgb(15, 17, 21);">。</span></li></ul><h3 id="_2-弥补检索器与生俱来的-粗糙-信号" tabindex="-1"><span style="color:rgb(15, 17, 21);">2. 弥补检索器与生俱来的“粗糙”信号</span> <a class="header-anchor" href="#_2-弥补检索器与生俱来的-粗糙-信号" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;2. 弥补检索器与生俱来的“粗糙”信号&lt;/span&gt;&quot;">​</a></h3><p><span style="color:rgb(15, 17, 21);">上一步使用的检索器（无论是基于稀疏的BM25还是稠密的向量检索），经常会产生“有相关性，但不太精准”的结果。</span></p><ul><li><strong><span style="color:rgb(15, 17, 21);">语义近似 ≠ 逻辑匹配</span></strong><span style="color:rgb(15, 17, 21);">：向量检索（如text-embeddings）依据的是宽泛的语义相似度。一个文档嵌入了和查询相似的词，就能获得高分，但它可能答非所问，或是只言片语擦边。比如查询“苹果最新macOS有什么新功能”，检索可能返回一篇讲“苹果公司历年财报”的文档，其语义相近，但完全不解决问题。</span></li><li><strong><span style="color:rgb(15, 17, 21);">重排做的是“精加工”</span></strong><span style="color:rgb(15, 17, 21);">：像</span><strong><span style="color:rgb(15, 17, 21);">交叉编码器</span></strong><span style="color:rgb(15, 17, 21);">，是把“查询”和“文档”完整地喂给一个深层Transformer模型做全息交互，它能读懂逻辑上的真正匹配度，而不是简单的向量余弦相似度。这种从“形似”到“神似”的飞跃，必须通过重排实现。</span></li></ul><h3 id="_3-应对成本与窗口的硬约束" tabindex="-1"><span style="color:rgb(15, 17, 21);">3. 应对成本与窗口的硬约束</span> <a class="header-anchor" href="#_3-应对成本与窗口的硬约束" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;3. 应对成本与窗口的硬约束&lt;/span&gt;&quot;">​</a></h3><ul><li><strong><span style="color:rgb(15, 17, 21);">经济账（Token成本）</span></strong><span style="color:rgb(15, 17, 21);">：检索器通常召回Top-100个文档。把100个长文档全塞进LLM，Token会瞬间爆炸，成本极高，且容易超过上下文窗口限制。重排相当于一个高性价比的“过滤器”，先用轻量模型把Top-100精准压缩成Top-5，再给LLM，成本可控且效果更佳。</span></li><li><strong><span style="color:rgb(15, 17, 21);">性能账（推理延迟）</span></strong><span style="color:rgb(15, 17, 21);">：输入长度是影响LLM生词速度的关键。输入越短，响应越快。精准重排后提供少量高质量文档，能带来极致的低延迟体验。</span></li></ul><h2 id="重排序-re-ranking" tabindex="-1"><span style="color:rgb(15, 17, 21);">重排序（Re-ranking）</span> <a class="header-anchor" href="#重排序-re-ranking" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;重排序（Re-ranking）&lt;/span&gt;&quot;">​</a></h2><p><span style="color:rgb(15, 17, 21);">在检索系统里，</span><strong><span style="color:rgb(15, 17, 21);">重排序（Re-ranking）</span></strong><span style="color:rgb(15, 17, 21);"> 的典型方法可以从技术演进的角度，归为三大类：经典学习排序（LTR）、基于预训练模型的深度语义重排，以及正在兴起的LLM重排。</span></p><h3 id="经典学习排序-ltr" tabindex="-1"><span style="color:rgb(15, 17, 21);">经典学习排序 (LTR)</span> <a class="header-anchor" href="#经典学习排序-ltr" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;经典学习排序 (LTR)&lt;/span&gt;&quot;">​</a></h3><ul><li><strong><span style="color:rgb(15, 17, 21);">Pointwise（逐点法）</span></strong><ul><li><strong><span style="color:rgb(15, 17, 21);">思路</span></strong><span style="color:rgb(15, 17, 21);">：将重排简化为二分类或回归问题，为每个文档独立预测一个绝对相关性分数，再按分数降序排列。</span></li><li><strong><span style="color:rgb(15, 17, 21);">典型代表</span></strong><span style="color:rgb(15, 17, 21);">：逻辑回归、GBDT、Ranking SVM等。</span></li><li><strong><span style="color:rgb(15, 17, 21);">特点</span></strong><span style="color:rgb(15, 17, 21);">：结构简单，训练快，但忽略了文档之间的相对顺序，排序结果可能不够精细。</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">Pairwise（逐对法）</span></strong><ul><li><strong><span style="color:rgb(15, 17, 21);">思路</span></strong><span style="color:rgb(15, 17, 21);">：聚焦于文档对的相对顺序。对于查询，模型判断文档A是否比文档B更相关，最终通过各种方法（如投票）将所有成对比较结果聚合成完整排序。</span></li><li><strong><span style="color:rgb(15, 17, 21);">典型代表</span></strong><span style="color:rgb(15, 17, 21);">：</span><strong><span style="color:rgb(15, 17, 21);">RankNet</span></strong><span style="color:rgb(15, 17, 21);">（基于神经网络）、</span><strong><span style="color:rgb(15, 17, 21);">LambdaRank</span></strong><span style="color:rgb(15, 17, 21);">（直接优化排序指标梯度，极大提升了效率）。</span></li><li><strong><span style="color:rgb(15, 17, 21);">特点</span></strong><span style="color:rgb(15, 17, 21);">：更贴近排序任务本质，性能通常优于Pointwise，但计算成本随文档数平方级增长。</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">Listwise（列表法）</span></strong><ul><li><strong><span style="color:rgb(15, 17, 21);">思路</span></strong><span style="color:rgb(15, 17, 21);">：输入整个候选文档列表，直接输出优化后的排序，或通过列表级损失函数（如NDCG）来优化模型，直接评价整个列表的质量。</span></li><li><strong><span style="color:rgb(15, 17, 21);">典型代表</span></strong><span style="color:rgb(15, 17, 21);">：</span><strong><span style="color:rgb(15, 17, 21);">LambdaMART</span></strong><span style="color:rgb(15, 17, 21);">（LambdaRank + 梯度提升树），是很多年来的SOTA基线；</span><strong><span style="color:rgb(15, 17, 21);">ListNet</span></strong><span style="color:rgb(15, 17, 21);">、</span><strong><span style="color:rgb(15, 17, 21);">SoftRank</span></strong><span style="color:rgb(15, 17, 21);">等。</span></li><li><strong><span style="color:rgb(15, 17, 21);">特点</span></strong><span style="color:rgb(15, 17, 21);">：效果通常最优，能直接优化业务指标，但训练复杂度最高。</span></li></ul></li></ul><h3 id="基于预训练模型的深度语义重排" tabindex="-1"><span style="color:rgb(15, 17, 21);">基于预训练模型的深度语义重排</span> <a class="header-anchor" href="#基于预训练模型的深度语义重排" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;基于预训练模型的深度语义重排&lt;/span&gt;&quot;">​</a></h3><ul><li><strong><span style="color:rgb(15, 17, 21);">交叉编码器 (Cross-Encoder)</span></strong><ul><li><strong><span style="color:rgb(15, 17, 21);">代表模型</span></strong><span style="color:rgb(15, 17, 21);">：</span><strong><span style="color:rgb(15, 17, 21);">monoBERT</span></strong><span style="color:rgb(15, 17, 21);">、</span><strong><span style="color:rgb(15, 17, 21);">monoT5</span></strong><span style="color:rgb(15, 17, 21);">。将查询和文档拼接后输入模型进行全交互注意力计算，输出一个精准的相关性分数。</span></li><li><strong><span style="color:rgb(15, 17, 21);">典型性</span></strong><span style="color:rgb(15, 17, 21);">：它是</span><strong><span style="color:rgb(15, 17, 21);">效果强基线</span></strong><span style="color:rgb(15, 17, 21);">，至今仍是很多产品的核心精排模块。离线工具如</span><code>rerankers</code><span style="color:rgb(15, 17, 21);">库就常集成</span><code>ms-marco-MiniLM</code><span style="color:rgb(15, 17, 21);">等轻量版交叉编码器。</span></li></ul></li><li><strong><span style="color:rgb(15, 17, 21);">ColBERT (后期交互)</span></strong><ul><li><strong><span style="color:rgb(15, 17, 21);">代表模型</span></strong><span style="color:rgb(15, 17, 21);">：</span><strong><span style="color:rgb(15, 17, 21);">ColBERT</span></strong><span style="color:rgb(15, 17, 21);">及其变体。</span></li><li><strong><span style="color:rgb(15, 17, 21);">典型性</span></strong><span style="color:rgb(15, 17, 21);">：它开创了</span><strong><span style="color:rgb(15, 17, 21);">“效率与效果平衡”的范式</span></strong><span style="color:rgb(15, 17, 21);">，通过提前离线计算并存储文档Token向量（向量索引），在线进行轻量级的MaxSim交互计算，使候选集可扩展至数千量级，在RAG系统中应用极广。</span></li></ul></li></ul><h3 id="基于llm的重排序" tabindex="-1"><span style="color:rgb(15, 17, 21);">基于LLM的重排序</span> <a class="header-anchor" href="#基于llm的重排序" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;基于LLM的重排序&lt;/span&gt;&quot;">​</a></h3><p><span style="color:rgb(15, 17, 21);">目前最典型的主要是围绕</span><strong><span style="color:rgb(15, 17, 21);">Listwise（列表重排）</span></strong><span style="color:rgb(15, 17, 21);">、</span><strong><span style="color:rgb(15, 17, 21);">Pairwise（成对比较）</span></strong><span style="color:rgb(15, 17, 21);"> 和</span><strong><span style="color:rgb(15, 17, 21);">知识蒸馏</span></strong><span style="color:rgb(15, 17, 21);">三个范式。</span></p><h4 id="_1-rankgpt-列表级重排的标杆-listwise" tabindex="-1"><span style="color:rgb(15, 17, 21);">1. RankGPT：列表级重排的标杆（Listwise）</span> <a class="header-anchor" href="#_1-rankgpt-列表级重排的标杆-listwise" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;1. RankGPT：列表级重排的标杆（Listwise）&lt;/span&gt;&quot;">​</a></h4><p><strong><span style="color:rgb(15, 17, 21);">操作方式</span></strong><span style="color:rgb(15, 17, 21);">：将候选文档按编号列表输入GPT等模型，通过精心设计的提示词（Prompt）让LLM直接输出重排后的编号顺序。</span><span style="color:rgb(15, 17, 21);"><br></span><strong><span style="color:rgb(15, 17, 21);">核心特点</span></strong><span style="color:rgb(15, 17, 21);">：</span></p><ul><li><strong><span style="color:rgb(15, 17, 21);">一次输出全局最优</span></strong><span style="color:rgb(15, 17, 21);">：模型利用自注意力机制同时关注所有文档，直接给出完整排序，最能发挥LLM的推理和全局比较能力。</span></li><li><strong><span style="color:rgb(15, 17, 21);">效果突出</span></strong><span style="color:rgb(15, 17, 21);">：在多个基准上刷新了零样本重排效果，是目前效果最佳的LLM重排方法之一。</span></li><li><strong><span style="color:rgb(15, 17, 21);">注意点</span></strong><span style="color:rgb(15, 17, 21);">：依赖强大的指令跟随能力，且对候选集大小敏感（通常Top-20/30），输出格式需进行后处理解析。</span></li></ul><h4 id="_2-prp-pairwise-ranking-prompting-精准成对比较-pairwise" tabindex="-1"><span style="color:rgb(15, 17, 21);">2. PRP（Pairwise Ranking Prompting）：精准成对比较（Pairwise）</span> <a class="header-anchor" href="#_2-prp-pairwise-ranking-prompting-精准成对比较-pairwise" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;2. PRP（Pairwise Ranking Prompting）：精准成对比较（Pairwise）&lt;/span&gt;&quot;">​</a></h4><p><strong><span style="color:rgb(15, 17, 21);">操作方式</span></strong><span style="color:rgb(15, 17, 21);">：对候选文档两两配对，每次让LLM判断“文档A是否比文档B更相关”，并输出比较结果及其置信度。最后将所有成对比较结果用图算法（如PRP-Graph）聚合成完整排序。</span><span style="color:rgb(15, 17, 21);"><br></span><strong><span style="color:rgb(15, 17, 21);">核心特点</span></strong><span style="color:rgb(15, 17, 21);">：</span></p><ul><li><strong><span style="color:rgb(15, 17, 21);">极其细腻</span></strong><span style="color:rgb(15, 17, 21);">：将复杂排序拆解为大量简单的两两对比，能捕捉到微小的相关性差异。</span></li><li><strong><span style="color:rgb(15, 17, 21);">质量可控</span></strong><span style="color:rgb(15, 17, 21);">：LLM可以直接输出比较的确定性（如高/中/低置信度），便于过滤不可靠比较，显著提升排序稳定性。</span></li><li><strong><span style="color:rgb(15, 17, 21);">适用场景</span></strong><span style="color:rgb(15, 17, 21);">：候选集较小但对排序精细度要求极高、且可以容忍较高计算开销的场景。</span></li></ul><h4 id="_3-first-速度至上的列表重排-listwise-加速版" tabindex="-1"><span style="color:rgb(15, 17, 21);">3. FIRST：速度至上的列表重排（Listwise 加速版）</span> <a class="header-anchor" href="#_3-first-速度至上的列表重排-listwise-加速版" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;3. FIRST：速度至上的列表重排（Listwise 加速版）&lt;/span&gt;&quot;">​</a></h4><p><strong><span style="color:rgb(15, 17, 21);">操作方式</span></strong><span style="color:rgb(15, 17, 21);">：同样输入整个文档列表，但让LLM只输出</span><strong><span style="color:rgb(15, 17, 21);">一个独立Token</span></strong><span style="color:rgb(15, 17, 21);">（如数字），直接从词表分布中解码出该Token指向的排序位置。</span><span style="color:rgb(15, 17, 21);"><br></span><strong><span style="color:rgb(15, 17, 21);">核心特点</span></strong><span style="color:rgb(15, 17, 21);">：</span></p><ul><li><strong><span style="color:rgb(15, 17, 21);">极致推理加速</span></strong><span style="color:rgb(15, 17, 21);">：将排序转化为单Token分类问题，避免了RankGPT等需要逐个解码文档编号的高延迟。</span></li><li><strong><span style="color:rgb(15, 17, 21);">兼顾效果</span></strong><span style="color:rgb(15, 17, 21);">：在保持一定排序质量的同时，速度提升显著，更适合对实时性有要求的在线服务。</span></li></ul><h4 id="_4-rank-distillm-工程落地的典范-知识蒸馏" tabindex="-1"><span style="color:rgb(15, 17, 21);">4. Rank-DistiLLM：工程落地的典范（知识蒸馏）</span> <a class="header-anchor" href="#_4-rank-distillm-工程落地的典范-知识蒸馏" aria-label="Permalink to &quot;&lt;span style=&quot;color:rgb(15, 17, 21);&quot;&gt;4. Rank-DistiLLM：工程落地的典范（知识蒸馏）&lt;/span&gt;&quot;">​</a></h4><p><strong><span style="color:rgb(15, 17, 21);">操作方式</span></strong><span style="color:rgb(15, 17, 21);">：先用RankGPT等高性能LLM对大量查询-文档对进行排序，生成高质量排序标签，再用这些标签去微调一个轻量级的交叉编码器（如DeBERTa-v3）。</span><span style="color:rgb(15, 17, 21);"><br></span><strong><span style="color:rgb(15, 17, 21);">核心特点</span></strong><span style="color:rgb(15, 17, 21);">：</span></p><ul><li><strong><span style="color:rgb(15, 17, 21);">将效果与效率解耦</span></strong><span style="color:rgb(15, 17, 21);">：继承了LLM卓越的语义排序能力，但推理时完全不需要LLM，一个轻量模型即可上线。</span></li><li><strong><span style="color:rgb(15, 17, 21);">超高性价比</span></strong><span style="color:rgb(15, 17, 21);">：原论文显示，蒸馏后的模型排序效果接近原始LLM，速度可提升</span><strong><span style="color:rgb(15, 17, 21);">100倍以上</span></strong><span style="color:rgb(15, 17, 21);">，显存占用仅为原来的</span><strong><span style="color:rgb(15, 17, 21);">1/24</span></strong><span style="color:rgb(15, 17, 21);">，是当前工业落地的最优策略之一。</span></li></ul>',31)])])}const u=r(a,[["render",t]]);export{y as __pageData,u as default};
